const stats = $('Fetch Weekly Procurement Stats').all();
const queue = $('Fetch Editorial Queue').all();
const weekEnd = new Date().toISOString().split('T')[0];
const weekStart = new Date(Date.now() - 7*24*60*60*1000).toISOString().split('T')[0];

let md = `# Reed Intel Weekly Report\n**Week: ${weekStart} → ${weekEnd}**\n\n`;
md += `## Procurement Activity\n| City | Sector | Events | Total Value |\n|------|--------|--------|-------------|\n`;
for (const row of stats) {
  md += `| ${row.json.city || '-'} | ${row.json.sector || '-'} | ${row.json.event_count} | ${row.json.total_value || 0} |\n`;
}
md += `\n## Editorial Priority Queue\n`;
for (const item of queue) {
  md += `### ${item.json.title}\n- **City:** ${item.json.city}  **Sector:** ${item.json.sector}\n- **Why it matters:** ${item.json.why_it_matters}\n- **Source:** ${item.json.source_url}\n\n`;
}

return [{ json: { report_markdown: md, week_start: weekStart, week_end: weekEnd } }];
